    },
    {
      "messageId": "19d5119a313181d0",
      "threadId": "19d5119a313181d0",
      "labelIds": [
        "IMPORTANT",
        "CATEGORY_PERSONAL",
        "INBOX"
      ],
      "snippet": "株式会社シュワン松窪様お世話になっております。 株式会社タンプ MDアシスタントの島村でございます。 ご連絡ありがとうございます。 貴社とは委託販売契約のため、納品時ではなく、実際にお客様が購入となった分が売上として計上されます。 売上も注文時に在庫は引き落とされ、発送時に売上が立つためタイムラグも発生いたします。 詳細はささげまたはMDよりお配りしましたマニュアルをご確認いただけますと幸いでござい",
      "historyId": "2349152",
      "internalDate": "1775182125000",
      "sizeEstimate": 7626,
      "headers": {
        "Date": "Fri, 03 Apr 2026 11:08:45 +0900",
