import { useState, useEffect } from 'react'

interface KpiRow {
  channel: string
  target: string
  actual: string
  forecast: string
  gap: string
  rating: string
}

interface ChanceRow {
  priority: string
  area: string
  content: string
  action: string
}

interface ActionRow {
  priority: string
  channel: string
  activity: string
  plan: string
  modification: string
  source: string
}

interface ParsedKpi {
  monthLabel: string
  rows: KpiRow[]
  annualTarget: string
  annualActual: string
  annualRate: string
  annualForecast: string
  chances: ChanceRow[]
  actions: ActionRow[]
}

function parseKpiData(md: string): ParsedKpi | null {
  const result: ParsedKpi = {
    monthLabel: '',
    rows: [],
    annualTarget: '',
    annualActual: '',
    annualRate: '',
    annualForecast: '',
    chances: [],
    actions: [],
  }

  // Parse month label from "### 当月（X月）着地見込"
  const monthMatch = md.match(/###\s*当月（(.+?)）着地見込/)
  result.monthLabel = monthMatch ? monthMatch[1] : ''

  // Parse KPI table from "着地見込・GAP分析" section
  const gapSection = md.split('## 着地見込・GAP分析')[1]
  if (!gapSection) return null

  const tableLines = gapSection.split('\n').filter(l => l.startsWith('|') && !l.includes('---'))
  let inKpiTable = false
  for (const line of tableLines) {
    const cols = line.split('|').map(c => c.trim()).filter(Boolean)
    if (cols.length < 6) continue
    if (cols[0] === 'チャネル') { inKpiTable = true; continue }
    if (cols[0] === '優先度' || cols[0] === '領域') { inKpiTable = false; continue }
    if (inKpiTable && cols[0] !== '—') {
      result.rows.push({
        channel: cols[0].replace(/\*\*/g, ''),
        target: cols[1].replace(/\*\*/g, ''),
        actual: cols[2].replace(/\*\*/g, ''),
        forecast: cols[3].replace(/\*\*/g, ''),
        gap: cols[4].replace(/\*\*/g, ''),
        rating: cols[5].replace(/\*\*/g, ''),
      })
    }
  }

  // Parse chances table
  const chancesHeader = gapSection.indexOf('### チャンス・課題サマリー')
  if (chancesHeader !== -1) {
    const chancesSection = gapSection.substring(chancesHeader)
    const chanceLines = chancesSection.split('\n').filter(l => l.startsWith('|') && !l.includes('---'))
    let started = false
    for (const line of chanceLines) {
      const cols = line.split('|').map(c => c.trim()).filter(Boolean)
      if (cols[0] === '領域' || cols[0] === '優先度') { started = true; continue }
      if (started && cols.length >= 4 && cols[0] !== '—') {
        result.chances.push({
          priority: cols.length >= 5 ? cols[0] : '',
          area: cols.length >= 5 ? cols[1] : cols[0],
          content: cols.length >= 5 ? cols[2] : cols[1],
          action: cols.length >= 5 ? cols[3] : cols[2],
        })
      }
    }
  }

  // Parse actions table
  const actionsHeader = gapSection.indexOf('### 活動修正提案')
  if (actionsHeader !== -1) {
    const actionsSection = gapSection.substring(actionsHeader)
    const actionLines = actionsSection.split('\n').filter(l => l.startsWith('|') && !l.includes('---'))
    let started = false
    for (const line of actionLines) {
      const cols = line.split('|').map(c => c.trim()).filter(Boolean)
      if (cols[0] === '優先度') { started = true; continue }
      if (started && cols.length >= 5 && cols[0] !== '—') {
        result.actions.push({
          priority: cols[0],
          channel: cols[1],
          activity: cols[2],
          plan: cols[3],
          modification: cols[4],
          source: cols.length >= 6 ? cols[5] : '',
        })
      }
    }
  }

  return result
}

function ratingColor(r: string) {
  if (r.includes('\u25CE')) return 'text-emerald-400' // ◎
  if (r.includes('\u25CB') || r.includes('○')) return 'text-blue-400'  // ○
  if (r.includes('\u25B3') || r.includes('△')) return 'text-amber-400' // △
  if (r.includes('\u00D7') || r.includes('×')) return 'text-red-400'   // ×
  return 'text-slate-400'
}

export default function KpiDashboard() {
  const [md, setMd] = useState<string | null>(null)
  const [expanded, setExpanded] = useState(true)

  useEffect(() => {
    fetch(`/api/kpi-tracking?t=${Date.now()}`)
      .then(r => r.json())
      .then(d => { if (d.content) setMd(d.content) })
      .catch(() => {})
  }, [])

  const data = md ? parseKpiData(md) : null
  const hasData = data && data.rows.length > 0 && data.rows.some(r => r.actual !== '—')

  return (
    <div className="rounded-xl border border-slate-700/50 bg-slate-800/30 p-5">
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <span className="text-base">📈</span>
          <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
            KPI進捗・GAP分析
          </h3>
          {data?.monthLabel && (
            <span className="text-[10px] px-2 py-0.5 rounded-full font-medium bg-blue-500/20 text-blue-400">
              {data.monthLabel}
            </span>
          )}
        </div>
        <button
          onClick={() => setExpanded(!expanded)}
          className="text-[10px] px-2 py-1 rounded bg-slate-700 text-slate-300 hover:bg-slate-600 transition-colors"
        >
          {expanded ? '折りたたむ' : '展開する'}
        </button>
      </div>

      {!md && (
        <p className="text-xs text-slate-500 animate-pulse">読み込み中...</p>
      )}

      {md && !hasData && (
        <div className="text-xs text-slate-500">
          <p>着地見込データ未入力（日次PDCA実行後に更新されます）</p>
          <div className="mt-2 flex flex-wrap gap-1.5">
            {data?.rows.filter(r => r.target !== '—').map(r => (
              <span key={r.channel} className="text-[10px] px-2 py-1 rounded bg-slate-700/60 text-slate-400">
                {r.channel}: 目標 {r.target}
              </span>
            ))}
          </div>
        </div>
      )}

      {hasData && expanded && (
        <div className="space-y-4">
          {/* KPI Progress Table */}
          <div>
            <h4 className="text-[11px] font-semibold text-slate-300 mb-2">当月 着地見込</h4>
            <div className="overflow-x-auto">
              <table className="w-full text-[10px]">
                <thead>
                  <tr className="text-slate-500 border-b border-slate-700/50">
                    <th className="text-left py-1 pr-2">チャネル</th>
                    <th className="text-right py-1 px-1">目標</th>
                    <th className="text-right py-1 px-1">実績</th>
                    <th className="text-right py-1 px-1">見込</th>
                    <th className="text-right py-1 px-1">GAP</th>
                    <th className="text-center py-1 pl-1">判定</th>
                  </tr>
                </thead>
                <tbody>
                  {data!.rows.map(row => (
                    <tr key={row.channel} className={`border-b border-slate-700/30 ${row.channel === '合計' ? 'font-bold text-slate-200' : 'text-slate-400'}`}>
                      <td className="py-1 pr-2 text-slate-300">{row.channel}</td>
                      <td className="text-right py-1 px-1 font-mono">{row.target}</td>
                      <td className="text-right py-1 px-1 font-mono">{row.actual}</td>
                      <td className="text-right py-1 px-1 font-mono">{row.forecast}</td>
                      <td className={`text-right py-1 px-1 font-mono ${row.gap.startsWith('-') || row.gap.startsWith('−') ? 'text-red-400' : row.gap.startsWith('+') ? 'text-emerald-400' : ''}`}>
                        {row.gap}
                      </td>
                      <td className={`text-center py-1 pl-1 font-bold ${ratingColor(row.rating)}`}>
                        {row.rating}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Chances & Issues */}
          {data!.chances.length > 0 && (
            <div>
              <h4 className="text-[11px] font-semibold text-slate-300 mb-2">チャンス・課題</h4>
              <div className="space-y-1.5">
                {data!.chances.map((c, i) => (
                  <div key={i} className="flex items-start gap-2 pl-1">
                    <span className={`text-[10px] mt-0.5 shrink-0 ${c.priority === '高' ? 'text-red-400' : c.priority === '中' ? 'text-amber-400' : 'text-slate-500'}`}>
                      {c.priority === '高' ? '!!!' : c.priority === '中' ? '!!' : '!'}
                    </span>
                    <div className="min-w-0">
                      <div className="flex items-center gap-1.5">
                        <span className="text-[10px] px-1.5 py-0.5 rounded bg-slate-700/60 text-slate-400 shrink-0">{c.area}</span>
                        <span className="text-[11px] text-slate-300">{c.content}</span>
                      </div>
                      <p className="text-[10px] text-slate-500 mt-0.5">{c.action}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Action Modifications */}
          {data!.actions.length > 0 && (
            <div>
              <h4 className="text-[11px] font-semibold text-slate-300 mb-2">活動修正提案</h4>
              <div className="space-y-1.5">
                {data!.actions.map((a, i) => (
                  <div key={i} className="flex items-start gap-2 pl-1">
                    <span className={`text-[10px] mt-0.5 shrink-0 font-bold ${a.priority === '高' ? 'text-red-400' : a.priority === '中' ? 'text-amber-400' : 'text-blue-400'}`}>
                      {a.priority}
                    </span>
                    <div className="min-w-0">
                      <span className="text-[11px] text-slate-300">
                        <span className="text-slate-500">[{a.channel}]</span> {a.activity}
                      </span>
                      <p className="text-[10px] text-emerald-400/80 mt-0.5">{a.modification}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {hasData && !expanded && (
        <div className="flex flex-wrap gap-1.5">
          {data!.rows.filter(r => r.channel !== '合計').map(r => (
            <span key={r.channel} className={`text-[10px] px-2 py-1 rounded bg-slate-700/60 ${ratingColor(r.rating)}`}>
              {r.channel} {r.rating} {r.gap}
            </span>
          ))}
        </div>
      )}
    </div>
  )
}

