import { useState, useEffect } from 'react'

interface KpiRow {
  channel: string
  target: string
  actual: string
  forecast: string
  gap: string
  rating: string
}

interface ChanceRow {
  priority: string
  area: string
  content: string
  action: string
}

interface ActionRow {
  priority: string
  channel: string
  activity: string
  plan: string
  modification: string
  source: string
}

interface ParsedKpi {
  monthLabel: string
  rows: KpiRow[]
  annualTarget: string
  annualActual: string
  annualRate: string
  annualForecast: string
  chances: ChanceRow[]
  actions: ActionRow[]
}

function parseKpiData(md: string): ParsedKpi | null {
  const result: ParsedKpi = {
    monthLabel: '',
